 1	import type { FC } from 'react';
 2	import { MigrationTypeValue } from 'src/plans/create/steps/migration-type/constants';
 3	
 4	import { Button, ButtonVariant, Label, Popover } from '@patternfly/react-core';
 5	import { useForkliftTranslation } from '@utils/i18n';
 6	
 7	import { bodyContent, typeLabel } from './utils/utils';
 8	
 9	import './PlanMigrationTypeLabel.scss';
10	
11	type PlanMigrationTypeLabelProps = {
12	  migrationType: MigrationTypeValue;
13	};
14	
15	const PlanMigrationTypeLabel: FC<PlanMigrationTypeLabelProps> = ({ migrationType }) => {
16	  const { t } = useForkliftTranslation();
17	
18	  return (
19	    <Popover
20	      headerContent={t('{{type}} migration', { type: typeLabel(migrationType) })}
21	      bodyContent={bodyContent(migrationType)}
22	      triggerAction="hover"
23	    >
24	      <Button className="forklift-plan-migration-type-label" variant={ButtonVariant.plain} isInline>
25	        <Label isCompact color={migrationType === MigrationTypeValue.Cold ? 'blue' : 'orange'}>
26	          {t('{{label}}', { label: typeLabel(migrationType) })}
27	        </Label>
28	      </Button>
29	    </Popover>
30	  );
31	};
32	
33	export default PlanMigrationTypeLabel;

